{
    "title": "6. Practice",
    "select_title": "Exercise 1. Choose the correct option",
    "select_intro": "Choose the correct Past Simple negative sentence.",
    "selects": [
        {
            "label": "a) I didn't see him yesterday. / b) I didn't saw him yesterday.",
            "prompt": "Which option is correct?",
            "answer": "a"
        },
        {
            "label": "a) She didn't went home early. / b) She didn't go home early.",
            "prompt": "Which option is correct?",
            "answer": "b"
        },
        {
            "label": "a) They did not finish the task. / b) They not finished the task.",
            "prompt": "Which option is correct?",
            "answer": "a"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Exercise 2. Make the sentence negative",
    "input_intro": "Rewrite the sentence in the negative Past Simple form.",
    "inputs": [
        {
            "before": "I saw Anna yesterday.",
            "after": "→",
            "answer": "I didn't see Anna yesterday.",
            "accepted": [
                "I didn't see Anna yesterday.",
                "I did not see Anna yesterday."
            ]
        },
        {
            "before": "She went to school last Monday.",
            "after": "→",
            "answer": "She didn't go to school last Monday.",
            "accepted": [
                "She didn't go to school last Monday.",
                "She did not go to school last Monday."
            ]
        },
        {
            "before": "They watched the film.",
            "after": "→",
            "answer": "They didn't watch the film.",
            "accepted": [
                "They didn't watch the film.",
                "They did not watch the film."
            ]
        }
    ],
    "rephrase_title": "Exercise 3. Correct the mistakes",
    "rephrase_intro": "Find the mistake in the negative sentence and write the correct version.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "He didn't went home.",
            "example_target": "He didn't go home."
        },
        {
            "original": "1. He didn't went home.",
            "placeholder": "Correct the sentence",
            "answer": "He didn't go home.",
            "accepted": [
                "He didn't go home.",
                "He did not go home."
            ]
        },
        {
            "original": "2. We didn't played well.",
            "placeholder": "Correct the sentence",
            "answer": "We didn't play well.",
            "accepted": [
                "We didn't play well.",
                "We did not play well."
            ]
        },
        {
            "original": "3. She not call me yesterday.",
            "placeholder": "Correct the sentence",
            "answer": "She didn't call me yesterday.",
            "accepted": [
                "She didn't call me yesterday.",
                "She did not call me yesterday."
            ]
        }
    ]
}
